  3	import {
  4	  type FC,
  5	  type MutableRefObject,
  6	  type ReactNode,
  7	  useCallback,
  8	  useEffect,
  9	  useMemo,
 10	  useRef,
 11	  useState,
 12	} from 'react';
 13	import { useForkliftTranslation } from 'src/utils/i18n';
 14	
 15	import TableBulkSelect from '@components/TableBulkSelect';
 16	import {
 17	  Flex,
 18	  FlexItem,
 19	  Icon,
 20	  Level,
 21	  LevelItem,
 22	  type OnPerPageSelect,
 23	  type OnSetPage,
 24	  PageSection,
 25	  Pagination,
 26	  Split,
 27	  Title,
 28	  Toolbar,
 29	  ToolbarContent,
 30	  ToolbarItem,
 31	  ToolbarToggleGroup,
 32	  Tooltip,
 33	} from '@patternfly/react-core';
 34	import { FilterIcon, HelpIcon } from '@patternfly/react-icons';
 35	import { isEmpty } from '@utils/helpers';
 36	
 37	import { AttributeValueFilter } from '../common/FilterGroup/AttributeValueFilter';
 38	import { FilterGroup } from '../common/FilterGroup/FilterGroup';
 39	import { toFieldFilter } from '../common/FilterGroup/helpers';
 40	import {
 41	  createMetaMatcher,
 42	  defaultSupportedFilters,
 43	  defaultValueMatchers,
 44	} from '../common/FilterGroup/matchers';
 45	import type { FilterRenderer, ValueMatcher } from '../common/FilterGroup/types';
 46	import { useUrlFilters } from '../common/FilterGroup/useUrlFilters';
 47	import {
 48	  ErrorState,
 49	  Loading,
 50	  NoResultsFound,
 51	  NoResultsMatchFilter,
 52	} from '../common/Page/PageStates';
 53	import type { UserSettings } from '../common/Page/types';
 54	import { useFields } from '../common/Page/useFields';
 55	import { DEFAULT_PER_PAGE, usePagination } from '../common/Page/usePagination';
 56	import { DefaultHeader } from '../common/TableView/DefaultHeader';
 57	import { DefaultRow } from '../common/TableView/DefaultRow';
 58	import { TableView } from '../common/TableView/TableView';
 59	import type { RowProps, TableViewHeaderProps } from '../common/TableView/types';
 60	import { withTr } from '../common/TableView/withTr';
 61	import type { GlobalActionToolbarProps, ResourceField } from '../common/utils/types';
 62	import {
 63	  TableSortContext,
 64	  type TableSortContextProps,
 65	  TableSortContextProvider,
 66	  useTableSortContext,
 67	} from '../TableSortContext';
 68	
 69	import { INITIAL_PAGE } from './utils/constants';
 70	import { reduceValueFilters } from './utils/reduceValueFilters';
 71	import { ManageColumnsToolbar } from './ManageColumnsToolbar';
 72	
 73	import './StandardPage.style.css';
 74	
 75	export type StandardPageProps<T> = {
 76	  dataSource: [T[], boolean, unknown];
 77	  fieldsMetadata: ResourceField[];
 78	  namespace: string;
 79	  page: number;
 80	
 81	  addButton?: JSX.Element;
 82	  RowMapper?: FC<RowProps<T>>;
 83	  CellMapper?: FC<RowProps<T>>;
 84	  ExpandedComponent?: FC<RowProps<T>>;
 85	  HeaderMapper?: FC<TableViewHeaderProps<T>>;
 86	  extraSupportedFilters?: Record<string, FilterRenderer>;
 87	  extraSupportedMatchers?: ValueMatcher[];
 88	  postFilterData?: (
 89	    data: T[],
 90	    selectedFilters: Record<string, string[]>,
 91	    fields: ResourceField[],
 92	  ) => T[];
 93	  customNoResultsFound?: JSX.Element;
 94	  customNoResultsMatchFilter?: JSX.Element;
 95	  pagination?: number | 'on' | 'off';
 96	  userSettings?: UserSettings;
 97	  alerts?: ReactNode;
 98	  GlobalActionToolbarItems?: FC<GlobalActionToolbarProps<T>>[];
 99	  className?: string;
100	  toId?: (item: T) => string;
101	  canSelect?: (item: T) => boolean;
102	  onSelect?: (selectedIds: string[]) => void;
103	  selectedIds?: string[];
104	  onExpand?: (expandedIds: string[]) => void;
105	  expandedIds?: string[];
106	  pageRef?: MutableRefObject<number>;
107	  showManageColumns?: boolean;
108	  title?: string;
109	  titleHelpContent?: ReactNode;
110	  noPadding?: boolean;
111	  testId?: string;
112	};
113	
114	type StandardPageInnerProps<T> = Omit<StandardPageProps<T>, 'pageRef'> &
115	  TableSortContextProps &
116	  Required<Pick<StandardPageProps<T>, 'pageRef'>>;
117	
118	const StandardPageInner = <T,>({
119	  activeSort,
120	  addButton,
121	  alerts,
122	  CellMapper,
123	  className,
124	  compareFn,
125	  customNoResultsFound,
126	  customNoResultsMatchFilter,
127	  dataSource: [flatData, loaded, error],
128	  expandedIds,
129	  extraSupportedFilters,
130	  extraSupportedMatchers,
131	  fieldsMetadata,
132	  GlobalActionToolbarItems = [],
133	  HeaderMapper = DefaultHeader<T>,
134	  namespace,
135	  noPadding,
136	  onSelect,
137	  page: initialPage,
138	  pageRef,
139	  pagination = DEFAULT_PER_PAGE,
140	  postFilterData,
141	  RowMapper = DefaultRow<T>,
142	  selectedIds,
143	  setActiveSort,
144	  showManageColumns = true,
145	  testId,
146	  title,
147	  titleHelpContent,
148	  toId,
149	  userSettings,
150	}: StandardPageInnerProps<T>) => {
151	  const { t } = useForkliftTranslation();
152	  const [sortedData, setSortedData] = useState<T[]>([]);
153	  const [filteredData, setFilteredData] = useState<T[]>([]);
154	  const [page, setPage] = useState(initialPage);
155	  const [finalFilteredData, setFinalFilteredData] = useState<T[]>([]);
156	
157	  const onPageSet = useCallback(
158	    (newPage: number) => {
159	      pageRef.current = newPage;
160	      setPage(newPage);
161	    },
162	    [pageRef],
163	  );
164	
165	  // Initialize page from ref on mount to handle cases where initialPage might change
166	  useEffect(() => {
167	    if (pageRef.current !== initialPage) {
168	      setPage(pageRef.current);
169	    }
170	  }, [initialPage, pageRef]);
171	
172	  const [selectedFilters, setSelectedFilters] = useUrlFilters({
173	    fields: fieldsMetadata,
174	    userSettings,
175	  });
176	
177	  const [fields, setFields] = useFields(namespace, fieldsMetadata, userSettings?.fields);
178	
179	  const supportedMatchers = useMemo(
180	    () =>
181	      extraSupportedMatchers
182	        ? reduceValueFilters(extraSupportedMatchers, defaultValueMatchers)
183	        : defaultValueMatchers,
184	    [extraSupportedMatchers],
185	  );
186	
187	  const supportedFilters = useMemo(
188	    () =>
189	      extraSupportedFilters
190	        ? { ...defaultSupportedFilters, ...extraSupportedFilters }
191	        : defaultSupportedFilters,
192	    [extraSupportedFilters],
193	  );
194	
195	  useEffect(() => {
196	    if (flatData && loaded && !error) {
197	      setSortedData([...flatData].sort(compareFn));
198	    }
199	  }, [flatData, compareFn, loaded, error]);
200	
201	  const metaMatcher = useMemo(
202	    () => createMetaMatcher(selectedFilters, fields, supportedMatchers),
203	    [selectedFilters, fields, supportedMatchers],
204	  );
205	
206	  useEffect(() => {
207	    if (sortedData && loaded && !error) {
208	      setFilteredData(sortedData.filter(metaMatcher));
209	    }
210	  }, [sortedData, metaMatcher, loaded, error]);
211	
212	  useEffect(() => {
213	    if (!loaded || error) {
214	      return;
215	    }
216	
217	    if (!filteredData || isEmpty(filteredData)) {
218	      setFinalFilteredData([]);
219	      return;
220	    }
221	
222	    if (!postFilterData) {
223	      setFinalFilteredData(filteredData);
224	      return;
225	    }
226	
227	    setFinalFilteredData(postFilterData(filteredData, selectedFilters, fields));
228	  }, [filteredData, postFilterData, selectedFilters, fields, loaded, error]);
229	
230	  useEffect(() => {
231	    if (Object.values(selectedFilters).some((filter) => !isEmpty(filter))) {
232	      setPage(INITIAL_PAGE); // When filters are applied, reset to page 1 to show correct results
233	    }
234	  }, [selectedFilters]);
235	
236	  const showPagination = useMemo(
237	    () => pagination === 'on' || (typeof pagination === 'number' && sortedData.length > pagination),
238	    [pagination, sortedData.length],
239	  );
240	
241	  const { itemsPerPage, setPerPage } = usePagination({
242	    filteredDataLength: finalFilteredData.length,
243	    userSettings: userSettings?.pagination,
244	  });
245	
246	  const pageData = useMemo(
247	    () => finalFilteredData.slice((page - 1) * itemsPerPage, page * itemsPerPage),
248	    [finalFilteredData, page, itemsPerPage],
249	  );
250	
251	  // Memoize error/loading states
252	  const errorFetchingData = useMemo(() => error, [error]);
253	  const noResults = useMemo(
254	    () => loaded && !error && isEmpty(sortedData),
255	    [loaded, error, sortedData],
256	  );
257	  const noMatchingResults = useMemo(
258	    () => loaded && !error && isEmpty(finalFilteredData) && !isEmpty(sortedData),
259	    [loaded, error, finalFilteredData, sortedData],
260	  );
261	
262	  const primaryFilters = useMemo(
263	    () => fields.filter((field) => field.filter?.primary).map(toFieldFilter(sortedData)),
264	    [fields, sortedData],
265	  );
266	
267	  const secondaryFilters = useMemo(
268	    () =>
269	      fields
270	        .filter(({ filter }) => filter && !filter.primary && !filter.standalone)
271	        .map(toFieldFilter(flatData)),
272	    [fields, flatData],
273	  );
274	
275	  const standaloneFilters = useMemo(
276	    () => fields.filter((field) => field.filter?.standalone).map(toFieldFilter(flatData)),
277	    [fields, flatData],
278	  );
279	
280	  const excludeFromClearFiltersIds = useMemo(
281	    () =>
282	      fields
283	        .filter((field) => field.filter?.excludeFromClearFilters)
284	        .map((field) => field.resourceFieldId),
285	    [fields],
286	  );
287	
288	  const selectedFiltersAfterClearAll = useMemo(
289	    () =>
290	      Object.fromEntries(
291	        Object.entries(selectedFilters).filter(([key]) => excludeFromClearFiltersIds.includes(key)),
292	      ),
293	    [excludeFromClearFiltersIds, selectedFilters],
294	  );
295	
296	  const clearAllFilters = useCallback(() => {
297	    setSelectedFilters(selectedFiltersAfterClearAll);
298	  }, [selectedFiltersAfterClearAll, setSelectedFilters]);
299	
300	  const visibleColumns = useMemo(
301	    () => fields.filter(({ isHidden, isVisible }) => isVisible && !isHidden),
302	    [fields],
303	  );
304	
305	  const onSetPage = useCallback<OnSetPage>(
306	    (_event, newPage) => {
307	      onPageSet(newPage);
308	    },
309	    [onPageSet],
310	  );
311	
312	  const onPerPageSelect = useCallback<OnPerPageSelect>(
313	    (_event, perPage, newPage) => {
314	      setPerPage(perPage);
315	      onPageSet(newPage);
316	    },
317	    [setPerPage, onPageSet],
318	  );
319	
320	  const RowComponent = useMemo(
321	    () => (CellMapper ? withTr(CellMapper) : RowMapper),
322	    [CellMapper, RowMapper],
323	  );
324	
325	  const dataOnScreen = useMemo(
326	    () => (showPagination ? pageData : finalFilteredData),
327	    [showPagination, pageData, finalFilteredData],
328	  );
329	
330	  const dataIds = useMemo(
331	    () => finalFilteredData?.map((data) => toId?.(data) ?? ''),
332	    [finalFilteredData, toId],
333	  );
334	
335	  const pageDataIds = useMemo(() => pageData?.map((data) => toId?.(data) ?? ''), [pageData, toId]);
336	
337	  const renderedGlobalActions = useMemo(
338	    () =>
339	      GlobalActionToolbarItems.map((Action, index) => (
340	        <Action key={`${Action.name}-${index}`} dataOnScreen={dataOnScreen} />
341	      )),
342	    [GlobalActionToolbarItems, dataOnScreen],
343	  );
344	
345	  return (
346	    <span className={className} data-testid={testId}>
347	      {title && (
348	        <PageSection variant="light" className="forklift-page__main-title">
349	          <Level>
350	            <LevelItem>
351	              <Flex
352	                alignItems={{ default: 'alignItemsCenter' }}
353	                spaceItems={{ default: 'spaceItemsSm' }}
354	              >
355	                <FlexItem>
356	                  <Title headingLevel="h1">{title}</Title>
357	                </FlexItem>
358	                {titleHelpContent && (
359	                  <FlexItem>
360	                    <Tooltip content={titleHelpContent}>
361	                      <Icon size="md">
362	                        <HelpIcon />
363	                      </Icon>
364	                    </Tooltip>
365	                  </FlexItem>
366	                )}
367	              </Flex>
368	            </LevelItem>
369	            {addButton && <LevelItem>{addButton}</LevelItem>}
370	          </Level>
371	        </PageSection>
372	      )}
373	      {alerts && <PageSection variant="light">{alerts}</PageSection>}
374	      <PageSection variant="light" padding={{ default: noPadding ? 'noPadding' : 'padding' }}>
375	        <Toolbar clearAllFilters={clearAllFilters} clearFiltersButtonText={t('Clear all filters')}>
376	          <ToolbarContent>
377	            <Split hasGutter>
378	              {selectedIds && onSelect && (
379	                <TableBulkSelect
380	                  selectedIds={selectedIds}
381	                  dataIds={dataIds}
382	                  pageDataIds={pageDataIds}
383	                  onSelect={onSelect}
384	                />
385	              )}
386	
387	              <ToolbarToggleGroup toggleIcon={<FilterIcon />} breakpoint="xl">
388	                {!isEmpty(primaryFilters) && (
389	                  <FilterGroup
390	                    fieldFilters={primaryFilters}
391	                    onFilterUpdate={setSelectedFilters}
392	                    selectedFilters={selectedFilters}
393	                    supportedFilterTypes={supportedFilters}
394	                  />
395	                )}
396	                <AttributeValueFilter
397	                  fieldFilters={secondaryFilters}
398	                  onFilterUpdate={setSelectedFilters}
399	                  selectedFilters={selectedFilters}
400	                  supportedFilterTypes={supportedFilters}
401	                />
402	                {Boolean(fields.find((field) => field.filter?.standalone)) && (
403	                  <FilterGroup
404	                    fieldFilters={standaloneFilters}
405	                    onFilterUpdate={setSelectedFilters}
406	                    selectedFilters={selectedFilters}
407	                    supportedFilterTypes={supportedFilters}
408	                  />
409	                )}
410	                {showManageColumns && (
411	                  <ManageColumnsToolbar
412	                    resourceFields={fields}
413	                    defaultColumns={fieldsMetadata}
414	                    setColumns={setFields}
415	                  />
416	                )}
417	                {!isEmpty(GlobalActionToolbarItems) && renderedGlobalActions}
418	              </ToolbarToggleGroup>
419	            </Split>
420	
421	            {showPagination && (
422	              <ToolbarItem variant="pagination">
423	                <Pagination
424	                  variant="top"
425	                  perPage={itemsPerPage}
426	                  page={page}
427	                  itemCount={finalFilteredData.length}
428	                  onSetPage={onSetPage}
429	                  onPerPageSelect={onPerPageSelect}
430	                />
431	              </ToolbarItem>
432	            )}
433	          </ToolbarContent>
434	        </Toolbar>
435	        <TableView<T>
436	          entities={dataOnScreen}
437	          visibleColumns={visibleColumns}
438	          aria-label={title ?? t('Page table')}
439	          Row={RowComponent}
440	          Header={HeaderMapper}
441	          activeSort={activeSort}
442	          setActiveSort={setActiveSort}
443	          currentNamespace={namespace}
444	          toId={toId}
445	          expandedIds={expandedIds}
446	        >
447	          {!loaded && !error && <Loading key="loading" title={t('Loading')} />}
448	          {Boolean(errorFetchingData) && (
449	            <ErrorState key="error" title={t('Unable to retrieve data')} />
450	          )}
451	          {noResults &&
452	            (customNoResultsFound ?? (
453	              <NoResultsFound key="no_result" title={t('No results found')} />
454	            ))}
455	          {noMatchingResults &&
456	            (customNoResultsMatchFilter ?? (
457	              <NoResultsMatchFilter
458	                key="no_match"
459	                clearAllFilters={clearAllFilters}
460	                title={t('No results found')}
461	                description={t(
462	                  'No results match the filter criteria. Clear all filters and try again.',
463	                )}
464	                clearAllLabel={t('Clear all filters')}
465	              />
466	            ))}
467	        </TableView>
468	        {showPagination && (
469	          <Pagination
470	            variant="bottom"
471	            perPage={itemsPerPage}
472	            page={page}
473	            itemCount={finalFilteredData.length}
474	            onSetPage={onSetPage}
475	            onPerPageSelect={onPerPageSelect}
476	          />
477	        )}
478	      </PageSection>
479	    </span>
480	  );
481	};
482	
483	const StandardPage = <T,>(pageProps: StandardPageProps<T>) => {
484	  const { activeSort, compareFn, setActiveSort } = useTableSortContext();
485	  const internalPageRef = useRef(pageProps.page);
486	  const pageRef = pageProps.pageRef ?? internalPageRef;
487	
488	  const defaultSort = useMemo(() => {
489	    const field = pageProps.fieldsMetadata.find((fld) => fld.defaultSortDirection);
490	    return field?.defaultSortDirection && field?.resourceFieldId
491	      ? { direction: field.defaultSortDirection, resourceFieldId: field.resourceFieldId }
492	      : undefined;
493	  }, [pageProps.fieldsMetadata]);
494	
495	  if (activeSort.resourceFieldId) {
496	    return (
497	      <StandardPageInner
498	        {...pageProps}
499	        activeSort={activeSort}
500	        setActiveSort={setActiveSort}
501	        compareFn={compareFn}
502	        pageRef={pageRef}
503	      />
504	    );
505	  }
506	
507	  return (
508	    <TableSortContextProvider fields={pageProps.fieldsMetadata} defaultSort={defaultSort}>
509	      <TableSortContext.Consumer>
510	        {(sortProps) => <StandardPageInner {...pageProps} {...sortProps} pageRef={pageRef} />}
511	      </TableSortContext.Consumer>
512	    </TableSortContextProvider>
513	  );
514	};
515	
516	export default StandardPage;

