 75	  dataSource: [T[], boolean, unknown];
 76	  fieldsMetadata: ResourceField[];
 77	  namespace: string;
 78	  page: number;
 79	
 80	  addButton?: JSX.Element;
 81	  RowMapper?: FC<RowProps<T>>;
 82	  CellMapper?: FC<RowProps<T>>;
 83	  ExpandedComponent?: FC<RowProps<T>>;
 84	  HeaderMapper?: FC<TableViewHeaderProps<T>>;
 85	  extraSupportedFilters?: Record<string, FilterRenderer>;
 86	  extraSupportedMatchers?: ValueMatcher[];
 87	  postFilterData?: (
 88	    data: T[],
 89	    selectedFilters: Record<string, string[]>,
 90	    fields: ResourceField[],
 91	  ) => T[];
 92	  customNoResultsFound?: JSX.Element;
 93	  customNoResultsMatchFilter?: JSX.Element;
 94	  pagination?: number | 'on' | 'off';
 95	  userSettings?: UserSettings;
 96	  alerts?: ReactNode;
 97	  GlobalActionToolbarItems?: FC<GlobalActionToolbarProps<T>>[];
 98	  className?: string;
 99	  toId?: (item: T) => string;
100	  canSelect?: (item: T) => boolean;
101	  onSelect?: (selectedIds: string[]) => void;
102	  selectedIds?: string[];
103	  onExpand?: (expandedIds: string[]) => void;
104	  expandedIds?: string[];
105	  pageRef?: MutableRefObject<number>;
106	  showManageColumns?: boolean;
107	  title?: string;
108	  titleHelpContent?: ReactNode;
109	  noPadding?: boolean;
110	  testId?: string;
111	};
112	
113	type StandardPageInnerProps<T> = Omit<StandardPageProps<T>, 'pageRef'> &
114	  TableSortContextProps &
115	  Required<Pick<StandardPageProps<T>, 'pageRef'>>;
116	
117	const StandardPageInner = <T,>({
118	  activeSort,
119	  addButton,
120	  alerts,
121	  CellMapper,
122	  className,
123	  compareFn,
124	  customNoResultsFound,
125	  customNoResultsMatchFilter,
126	  dataSource: [flatData, loaded, error],
127	  expandedIds,
128	  extraSupportedFilters,
129	  extraSupportedMatchers,
130	  fieldsMetadata,
131	  GlobalActionToolbarItems = [],
132	  HeaderMapper = DefaultHeader<T>,
133	  namespace,
134	  noPadding,
135	  onSelect,
136	  page: initialPage,
137	  pageRef,
138	  pagination = DEFAULT_PER_PAGE,
139	  postFilterData,
140	  RowMapper = DefaultRow<T>,
141	  selectedIds,
142	  setActiveSort,
143	  showManageColumns = true,
144	  testId,
145	  title,
146	  titleHelpContent,
147	  toId,
148	  userSettings,
149	}: StandardPageInnerProps<T>) => {
150	  const { t } = useForkliftTranslation();
151	  const [sortedData, setSortedData] = useState<T[]>([]);
152	  const [filteredData, setFilteredData] = useState<T[]>([]);
153	  const [page, setPage] = useState(initialPage);
154	  const [finalFilteredData, setFinalFilteredData] = useState<T[]>([]);
155	
156	  const onPageSet = useCallback(
157	    (newPage: number) => {
158	      pageRef.current = newPage;
159	      setPage(newPage);
160	    },
161	    [pageRef],
162	  );
163	
164	  // Initialize page from ref on mount to handle cases where initialPage might change
165	  useEffect(() => {
166	    if (pageRef.current !== initialPage) {
167	      setPage(pageRef.current);
168	    }
169	  }, [initialPage, pageRef]);
170	
171	  const [selectedFilters, setSelectedFilters] = useUrlFilters({
172	    fields: fieldsMetadata,
173	    userSettings,
174	  });
175	
176	  const [fields, setFields] = useFields(namespace, fieldsMetadata, userSettings?.fields);
177	
178	  const supportedMatchers = useMemo(
179	    () =>
180	      extraSupportedMatchers
181	        ? reduceValueFilters(extraSupportedMatchers, defaultValueMatchers)
182	        : defaultValueMatchers,
183	    [extraSupportedMatchers],
184	  );
185	
186	  const supportedFilters = useMemo(
187	    () =>
188	      extraSupportedFilters
189	        ? { ...defaultSupportedFilters, ...extraSupportedFilters }
190	        : defaultSupportedFilters,
191	    [extraSupportedFilters],
192	  );
193	
194	  useEffect(() => {
195	    if (flatData && loaded && !error) {
196	      setSortedData([...flatData].sort(compareFn));
197	    }
198	  }, [flatData, compareFn, loaded, error]);
199	
200	  const metaMatcher = useMemo(
201	    () => createMetaMatcher(selectedFilters, fields, supportedMatchers),
202	    [selectedFilters, fields, supportedMatchers],
203	  );
204	
205	  useEffect(() => {
206	    if (sortedData && loaded && !error) {
207	      setFilteredData(sortedData.filter(metaMatcher));
208	    }
209	  }, [sortedData, metaMatcher, loaded, error]);
210	
211	  useEffect(() => {
212	    if (!loaded || error) {
213	      return;
214	    }
215	
216	    if (!filteredData || isEmpty(filteredData)) {
217	      setFinalFilteredData([]);
218	      return;
219	    }
220	
221	    if (!postFilterData) {
222	      setFinalFilteredData(filteredData);
223	      return;
224	    }
225	
226	    setFinalFilteredData(postFilterData(filteredData, selectedFilters, fields));
227	  }, [filteredData, postFilterData, selectedFilters, fields, loaded, error]);
228	
229	  useEffect(() => {
230	    if (Object.values(selectedFilters).some((filter) => !isEmpty(filter))) {
231	      setPage(INITIAL_PAGE); // When filters are applied, reset to page 1 to show correct results
232	    }
233	  }, [selectedFilters]);
234	
235	  const showPagination = useMemo(
236	    () => pagination === 'on' || (typeof pagination === 'number' && sortedData.length > pagination),
237	    [pagination, sortedData.length],
238	  );
239	
240	  const { itemsPerPage, setPerPage } = usePagination({
241	    filteredDataLength: finalFilteredData.length,
242	    userSettings: userSettings?.pagination,
243	  });
244	
245	  const pageData = useMemo(
246	    () => finalFilteredData.slice((page - 1) * itemsPerPage, page * itemsPerPage),
247	    [finalFilteredData, page, itemsPerPage],
248	  );
249	
250	  // Memoize error/loading states
251	  const errorFetchingData = useMemo(() => error, [error]);
252	  const noResults = useMemo(
253	    () => loaded && !error && isEmpty(sortedData),
254	    [loaded, error, sortedData],
255	  );
256	  const noMatchingResults = useMemo(
257	    () => loaded && !error && isEmpty(finalFilteredData) && !isEmpty(sortedData),
258	    [loaded, error, finalFilteredData, sortedData],
259	  );
260	
261	  const primaryFilters = useMemo(
262	    () => fields.filter((field) => field.filter?.primary).map(toFieldFilter(sortedData)),
263	    [fields, sortedData],
264	  );
265	
266	  const secondaryFilters = useMemo(
267	    () =>
268	      fields
269	        .filter(({ filter }) => filter && !filter.primary && !filter.standalone)
270	        .map(toFieldFilter(flatData)),
271	    [fields, flatData],
272	  );
273	
274	  const standaloneFilters = useMemo(
275	    () => fields.filter((field) => field.filter?.standalone).map(toFieldFilter(flatData)),
276	    [fields, flatData],
277	  );
278	
279	  const excludeFromClearFiltersIds = useMemo(
280	    () =>
281	      fields
282	        .filter((field) => field.filter?.excludeFromClearFilters)
283	        .map((field) => field.resourceFieldId),
284	    [fields],
285	  );
286	
287	  const selectedFiltersAfterClearAll = useMemo(
288	    () =>
289	      Object.fromEntries(
290	        Object.entries(selectedFilters).filter(([key]) => excludeFromClearFiltersIds.includes(key)),
291	      ),
292	    [excludeFromClearFiltersIds, selectedFilters],
293	  );
294	
295	  const clearAllFilters = useCallback(() => {
296	    setSelectedFilters(selectedFiltersAfterClearAll);
297	  }, [selectedFiltersAfterClearAll, setSelectedFilters]);
298	
299	  const visibleColumns = useMemo(
300	    () => fields.filter(({ isHidden, isVisible }) => isVisible && !isHidden),
301	    [fields],
302	  );
303	
304	  const onSetPage = useCallback<OnSetPage>(
305	    (_event, newPage) => {
306	      onPageSet(newPage);
307	    },
308	    [onPageSet],
309	  );
310	
311	  const onPerPageSelect = useCallback<OnPerPageSelect>(
312	    (_event, perPage, newPage) => {
313	      setPerPage(perPage);
314	      onPageSet(newPage);
315	    },
316	    [setPerPage, onPageSet],
317	  );
318	
319	  const RowComponent = useMemo(
320	    () => (CellMapper ? withTr(CellMapper) : RowMapper),
321	    [CellMapper, RowMapper],
322	  );
323	
324	  const dataOnScreen = useMemo(
325	    () => (showPagination ? pageData : finalFilteredData),
326	    [showPagination, pageData, finalFilteredData],
327	  );
328	
329	  const dataIds = useMemo(
330	    () => finalFilteredData?.map((data) => toId?.(data) ?? ''),
331	    [finalFilteredData, toId],
332	  );
333	
334	  const pageDataIds = useMemo(() => pageData?.map((data) => toId?.(data) ?? ''), [pageData, toId]);
335	
336	  const renderedGlobalActions = useMemo(
337	    () =>
338	      GlobalActionToolbarItems.map((Action, index) => (
339	        <Action key={`${Action.name}-${index}`} dataOnScreen={dataOnScreen} />
340	      )),
341	    [GlobalActionToolbarItems, dataOnScreen],
342	  );
343	
344	  return (
345	    <span className={className} data-testid={testId}>
346	      {title && (
347	        <PageSection variant="default" className="forklift-page__main-title">
348	          <Level>
349	            <LevelItem>
350	              <Flex
351	                alignItems={{ default: 'alignItemsCenter' }}
352	                spaceItems={{ default: 'spaceItemsSm' }}
353	              >
354	                <FlexItem>
355	                  <Title headingLevel="h1">{title}</Title>
356	                </FlexItem>
357	                {titleHelpContent && (
358	                  <FlexItem>
359	                    <Tooltip content={titleHelpContent}>
360	                      <HelpIcon />
361	                    </Tooltip>
362	                  </FlexItem>
363	                )}
364	              </Flex>
365	            </LevelItem>
366	            {addButton && <LevelItem>{addButton}</LevelItem>}
367	          </Level>
368	        </PageSection>
369	      )}
370	      {alerts && <PageSection variant="default">{alerts}</PageSection>}
371	      <PageSection variant="default" padding={{ default: noPadding ? 'noPadding' : 'padding' }}>
372	        <Toolbar clearAllFilters={clearAllFilters} clearFiltersButtonText={t('Clear all filters')}>
373	          <ToolbarContent>
374	            <Split hasGutter>
375	              {selectedIds && onSelect && (
376	                <TableBulkSelect
377	                  selectedIds={selectedIds}
378	                  dataIds={dataIds}
379	                  pageDataIds={pageDataIds}
380	                  onSelect={onSelect}
381	                />
382	              )}
383	
384	              <ToolbarToggleGroup toggleIcon={<FilterIcon />} breakpoint="xl">
385	                {!isEmpty(primaryFilters) && (
386	                  <FilterGroup
387	                    fieldFilters={primaryFilters}
388	                    onFilterUpdate={setSelectedFilters}
389	                    selectedFilters={selectedFilters}
390	                    supportedFilterTypes={supportedFilters}
391	                  />
392	                )}
393	                <AttributeValueFilter
394	                  fieldFilters={secondaryFilters}
395	                  onFilterUpdate={setSelectedFilters}
396	                  selectedFilters={selectedFilters}
397	                  supportedFilterTypes={supportedFilters}
398	                />
399	                {Boolean(fields.find((field) => field.filter?.standalone)) && (
400	                  <FilterGroup
401	                    fieldFilters={standaloneFilters}
402	                    onFilterUpdate={setSelectedFilters}
403	                    selectedFilters={selectedFilters}
404	                    supportedFilterTypes={supportedFilters}
405	                  />
406	                )}
407	                {showManageColumns && (
408	                  <ManageColumnsToolbar
409	                    resourceFields={fields}
410	                    defaultColumns={fieldsMetadata}
411	                    setColumns={setFields}
412	                  />
413	                )}
414	                {!isEmpty(GlobalActionToolbarItems) && renderedGlobalActions}
415	              </ToolbarToggleGroup>
416	            </Split>
417	
418	            {showPagination && (
419	              <ToolbarItem variant="pagination">
420	                <Pagination
421	                  variant="top"
422	                  perPage={itemsPerPage}
423	                  page={page}
424	                  itemCount={finalFilteredData.length}
425	                  onSetPage={onSetPage}
426	                  onPerPageSelect={onPerPageSelect}
427	                />
428	              </ToolbarItem>
429	            )}
430	          </ToolbarContent>
431	        </Toolbar>
432	        <TableView<T>
433	          entities={dataOnScreen}
434	          visibleColumns={visibleColumns}
435	          aria-label={title ?? t('Page table')}
436	          Row={RowComponent}
437	          Header={HeaderMapper}
438	          activeSort={activeSort}
439	          setActiveSort={setActiveSort}
440	          currentNamespace={namespace}
441	          toId={toId}
442	          expandedIds={expandedIds}
443	        >
444	          {!loaded && !error && <Loading key="loading" title={t('Loading')} />}
445	          {Boolean(errorFetchingData) && (
446	            <ErrorState key="error" title={t('Unable to retrieve data')} />
447	          )}
448	          {noResults &&
449	            (customNoResultsFound ?? (
450	              <NoResultsFound key="no_result" title={t('No results found')} />
451	            ))}
452	          {noMatchingResults &&
453	            (customNoResultsMatchFilter ?? (
454	              <NoResultsMatchFilter
455	                key="no_match"
456	                clearAllFilters={clearAllFilters}
457	                title={t('No results found')}
458	                description={t(
459	                  'No results match the filter criteria. Clear all filters and try again.',
460	                )}
461	                clearAllLabel={t('Clear all filters')}
462	              />
463	            ))}
464	        </TableView>
465	        {showPagination && (
466	          <Pagination
467	            variant="bottom"
468	            perPage={itemsPerPage}
469	            page={page}
470	            itemCount={finalFilteredData.length}
471	            onSetPage={onSetPage}
472	            onPerPageSelect={onPerPageSelect}
473	          />
474	        )}
475	      </PageSection>
476	    </span>
477	  );
478	};
479	
480	const StandardPage = <T,>(pageProps: StandardPageProps<T>) => {
481	  const { activeSort, compareFn, setActiveSort } = useTableSortContext();
482	  const internalPageRef = useRef(pageProps.page);
483	  const pageRef = pageProps.pageRef ?? internalPageRef;
484	
485	  const defaultSort = useMemo(() => {
486	    const field = pageProps.fieldsMetadata.find((fld) => fld.defaultSortDirection);
487	    return field?.defaultSortDirection && field?.resourceFieldId
488	      ? { direction: field.defaultSortDirection, resourceFieldId: field.resourceFieldId }
489	      : undefined;
490	  }, [pageProps.fieldsMetadata]);
491	
492	  if (activeSort.resourceFieldId) {
493	    return (
494	      <StandardPageInner
495	        {...pageProps}
496	        activeSort={activeSort}
497	        setActiveSort={setActiveSort}
498	        compareFn={compareFn}
499	        pageRef={pageRef}
500	      />
501	    );
502	  }
503	
504	  return (
505	    <TableSortContextProvider fields={pageProps.fieldsMetadata} defaultSort={defaultSort}>
506	      <TableSortContext.Consumer>
507	        {(sortProps) => <StandardPageInner {...pageProps} {...sortProps} pageRef={pageRef} />}
508	      </TableSortContext.Consumer>
509	    </TableSortContextProvider>
510	  );
511	};
512	
513	export default StandardPage;

