  1	/* eslint-disable max-lines */
  2	/* eslint-disable max-lines-per-function */
  3	import {
  4	  type FC,
  5	  type MutableRefObject,
  6	  type ReactNode,
  7	  useCallback,
  8	  useEffect,
  9	  useMemo,
 10	  useRef,
 11	  useState,
 12	} from 'react';
 13	import { useForkliftTranslation } from 'src/utils/i18n';
 14	
 15	import TableBulkSelect from '@components/TableBulkSelect';
 16	import {
 17	  Flex,
 18	  FlexItem,
 19	  Level,
 20	  LevelItem,
 21	  type OnPerPageSelect,
 22	  type OnSetPage,
 23	  PageSection,
 24	  Pagination,
 25	  Title,
 26	  Toolbar,
 27	  ToolbarContent,
 28	  ToolbarItem,
 29	  ToolbarToggleGroup,
 30	  Tooltip,
 31	} from '@patternfly/react-core';
 32	import { FilterIcon, HelpIcon } from '@patternfly/react-icons';
 33	import { isEmpty } from '@utils/helpers';
 34	
 35	import { AttributeValueFilter } from '../common/FilterGroup/AttributeValueFilter';
 36	import { FilterGroup } from '../common/FilterGroup/FilterGroup';
 37	import { toFieldFilter } from '../common/FilterGroup/helpers';
 38	import {
 39	  createMetaMatcher,
 40	  defaultSupportedFilters,
 41	  defaultValueMatchers,
 42	} from '../common/FilterGroup/matchers';
 43	import type { FilterRenderer, ValueMatcher } from '../common/FilterGroup/types';
 44	import { useUrlFilters } from '../common/FilterGroup/useUrlFilters';
 45	import {
 46	  ErrorState,
 47	  Loading,
 48	  NoResultsFound,
 49	  NoResultsMatchFilter,
 50	} from '../common/Page/PageStates';
 51	import type { UserSettings } from '../common/Page/types';
 52	import { useFields } from '../common/Page/useFields';
 53	import { DEFAULT_PER_PAGE, usePagination } from '../common/Page/usePagination';
 54	import { DefaultHeader } from '../common/TableView/DefaultHeader';
 55	import { DefaultRow } from '../common/TableView/DefaultRow';
 56	import { TableView } from '../common/TableView/TableView';
 57	import type { RowProps, TableViewHeaderProps } from '../common/TableView/types';
 58	import { withTr } from '../common/TableView/withTr';
 59	import type { GlobalActionToolbarProps, ResourceField } from '../common/utils/types';
 60	import {
 61	  TableSortContext,
 62	  type TableSortContextProps,
 63	  TableSortContextProvider,
 64	  useTableSortContext,
 65	} from '../TableSortContext';
 66	
 67	import { INITIAL_PAGE } from './utils/constants';
 68	import { reduceValueFilters } from './utils/reduceValueFilters';
 69	import { ManageColumnsToolbar } from './ManageColumnsToolbar';
 70	
 71	import './StandardPage.style.css';
 72	
 73	export type StandardPageProps<T> = {
 74	  dataSource: [T[], boolean, unknown];
 75	  fieldsMetadata: ResourceField[];
 76	  namespace: string;
 77	  page: number;
 78	
 79	  addButton?: JSX.Element;
 80	  RowMapper?: FC<RowProps<T>>;
 81	  CellMapper?: FC<RowProps<T>>;
 82	  ExpandedComponent?: FC<RowProps<T>>;
 83	  HeaderMapper?: FC<TableViewHeaderProps<T>>;
 84	  extraSupportedFilters?: Record<string, FilterRenderer>;
 85	  extraSupportedMatchers?: ValueMatcher[];
 86	  postFilterData?: (
 87	    data: T[],
 88	    selectedFilters: Record<string, string[]>,
 89	    fields: ResourceField[],
 90	  ) => T[];
 91	  customNoResultsFound?: JSX.Element;
 92	  customNoResultsMatchFilter?: JSX.Element;
 93	  pagination?: number | 'on' | 'off';
 94	  userSettings?: UserSettings;
 95	  alerts?: ReactNode;
 96	  GlobalActionToolbarItems?: FC<GlobalActionToolbarProps<T>>[];
 97	  className?: string;
 98	  toId?: (item: T) => string;
 99	  canSelect?: (item: T) => boolean;
100	  onSelect?: (selectedIds: string[]) => void;
101	  selectedIds?: string[];
102	  onExpand?: (expandedIds: string[]) => void;
103	  expandedIds?: string[];
104	  pageRef?: MutableRefObject<number>;
105	  showManageColumns?: boolean;
106	  title?: string;
107	  titleHelpContent?: ReactNode;
108	  noPadding?: boolean;
109	  testId?: string;
110	};
111	
112	type StandardPageInnerProps<T> = Omit<StandardPageProps<T>, 'pageRef'> &
113	  TableSortContextProps &
114	  Required<Pick<StandardPageProps<T>, 'pageRef'>>;
115	
116	const StandardPageInner = <T,>({
117	  activeSort,
118	  addButton,
119	  alerts,
120	  CellMapper,
121	  className,
122	  compareFn,
123	  customNoResultsFound,
124	  customNoResultsMatchFilter,
125	  dataSource: [flatData, loaded, error],
126	  expandedIds,
127	  extraSupportedFilters,
128	  extraSupportedMatchers,
129	  fieldsMetadata,
130	  GlobalActionToolbarItems = [],
131	  HeaderMapper = DefaultHeader<T>,
132	  namespace,
133	  noPadding,
134	  onSelect,
135	  page: initialPage,
136	  pageRef,
137	  pagination = DEFAULT_PER_PAGE,
138	  postFilterData,
139	  RowMapper = DefaultRow<T>,
140	  selectedIds,
141	  setActiveSort,
142	  showManageColumns = true,
143	  testId,
144	  title,
145	  titleHelpContent,
146	  toId,
147	  userSettings,
148	}: StandardPageInnerProps<T>) => {
149	  const { t } = useForkliftTranslation();
150	  const [sortedData, setSortedData] = useState<T[]>([]);
151	  const [filteredData, setFilteredData] = useState<T[]>([]);
152	  const [page, setPage] = useState(initialPage);
153	  const [finalFilteredData, setFinalFilteredData] = useState<T[]>([]);
154	
155	  const onPageSet = useCallback(
156	    (newPage: number) => {
157	      pageRef.current = newPage;
158	      setPage(newPage);
159	    },
160	    [pageRef],
161	  );
162	
163	  // Initialize page from ref on mount to handle cases where initialPage might change
164	  useEffect(() => {
165	    if (pageRef.current !== initialPage) {
166	      setPage(pageRef.current);
167	    }
168	  }, [initialPage, pageRef]);
169	
170	  const [selectedFilters, setSelectedFilters] = useUrlFilters({
171	    fields: fieldsMetadata,
172	    userSettings,
173	  });
174	
175	  const [fields, setFields] = useFields(namespace, fieldsMetadata, userSettings?.fields);
