479	const StandardPage = <T,>(pageProps: StandardPageProps<T>) => {
480	  const { activeSort, compareFn, setActiveSort } = useTableSortContext();
481	  const internalPageRef = useRef(pageProps.page);
482	  const pageRef = pageProps.pageRef ?? internalPageRef;
483	
484	  const defaultSort = useMemo(() => {
485	    const field = pageProps.fieldsMetadata.find((fld) => fld.defaultSortDirection);
486	    return field?.defaultSortDirection && field?.resourceFieldId
487	      ? { direction: field.defaultSortDirection, resourceFieldId: field.resourceFieldId }
488	      : undefined;
489	  }, [pageProps.fieldsMetadata]);
490	
491	  if (activeSort.resourceFieldId) {
492	    return (
493	      <StandardPageInner
494	        {...pageProps}
495	        activeSort={activeSort}
496	        setActiveSort={setActiveSort}
497	        compareFn={compareFn}
498	        pageRef={pageRef}
499	      />
500	    );
501	  }
502	
503	  return (
504	    <TableSortContextProvider fields={pageProps.fieldsMetadata} defaultSort={defaultSort}>
505	      <TableSortContext.Consumer>
506	        {(sortProps) => <StandardPageInner {...pageProps} {...sortProps} pageRef={pageRef} />}
507	      </TableSortContext.Consumer>
508	    </TableSortContextProvider>
509	  );
510	};
