350	                alignItems={{ default: 'alignItemsCenter' }}
351	                spaceItems={{ default: 'spaceItemsSm' }}
352	              >
353	                <FlexItem>
354	                  <Title headingLevel="h1">{title}</Title>
355	                </FlexItem>
356	                {titleHelpContent && (
357	                  <FlexItem>
358	                    <Tooltip content={titleHelpContent}>
359	                      <HelpIcon />
360	                    </Tooltip>
361	                  </FlexItem>
362	                )}
363	              </Flex>
364	            </LevelItem>
365	            {addButton && <LevelItem>{addButton}</LevelItem>}
366	          </Level>
367	        </PageSection>
368	      )}
369	      {alerts && <PageSection variant="default">{alerts}</PageSection>}
370	      <PageSection variant="default" padding={{ default: noPadding ? 'noPadding' : 'padding' }}>
371	        <Toolbar clearAllFilters={clearAllFilters} clearFiltersButtonText={t('Clear all filters')}>
372	          <ToolbarContent>
373	              {selectedIds && onSelect && (
374	                <ToolbarItem>
375	                  <TableBulkSelect
376	                    selectedIds={selectedIds}
377	                    dataIds={dataIds}
378	                    pageDataIds={pageDataIds}
379	                    onSelect={onSelect}
380	                  />
381	                </ToolbarItem>
382	              )}
383	
384	              <ToolbarToggleGroup toggleIcon={<FilterIcon />} breakpoint="xl">
385	                {!isEmpty(primaryFilters) && (
386	                  <FilterGroup
387	                    fieldFilters={primaryFilters}
388	                    onFilterUpdate={setSelectedFilters}
389	                    selectedFilters={selectedFilters}
390	                    supportedFilterTypes={supportedFilters}
391	                  />
392	                )}
393	                <AttributeValueFilter
394	                  fieldFilters={secondaryFilters}
395	                  onFilterUpdate={setSelectedFilters}
396	                  selectedFilters={selectedFilters}
397	                  supportedFilterTypes={supportedFilters}
398	                />
399	                {Boolean(fields.find((field) => field.filter?.standalone)) && (
400	                  <FilterGroup
401	                    fieldFilters={standaloneFilters}
402	                    onFilterUpdate={setSelectedFilters}
403	                    selectedFilters={selectedFilters}
404	                    supportedFilterTypes={supportedFilters}
405	                  />
406	                )}
407	                {showManageColumns && (
408	                  <ManageColumnsToolbar
409	                    resourceFields={fields}
410	                    defaultColumns={fieldsMetadata}
411	                    setColumns={setFields}
412	                  />
413	                )}
414	                {!isEmpty(GlobalActionToolbarItems) && renderedGlobalActions}
415	              </ToolbarToggleGroup>
416	
417	            {showPagination && (
418	              <ToolbarItem variant="pagination">
419	                <Pagination
420	                  variant="top"
421	                  perPage={itemsPerPage}
422	                  page={page}
423	                  itemCount={finalFilteredData.length}
424	                  onSetPage={onSetPage}
425	                  onPerPageSelect={onPerPageSelect}
426	                />
427	              </ToolbarItem>
428	            )}
429	          </ToolbarContent>
430	        </Toolbar>
431	        <TableView<T>
432	          entities={dataOnScreen}
433	          visibleColumns={visibleColumns}
434	          aria-label={title ?? t('Page table')}
435	          Row={RowComponent}
436	          Header={HeaderMapper}
437	          activeSort={activeSort}
438	          setActiveSort={setActiveSort}
439	          currentNamespace={namespace}
440	          toId={toId}
441	          expandedIds={expandedIds}
442	        >
443	          {!loaded && !error && <Loading key="loading" title={t('Loading')} />}
444	          {Boolean(errorFetchingData) && (
445	            <ErrorState key="error" title={t('Unable to retrieve data')} />
446	          )}
447	          {noResults &&
448	            (customNoResultsFound ?? (
449	              <NoResultsFound key="no_result" title={t('No results found')} />
450	            ))}
451	          {noMatchingResults &&
452	            (customNoResultsMatchFilter ?? (
453	              <NoResultsMatchFilter
454	                key="no_match"
455	                clearAllFilters={clearAllFilters}
456	                title={t('No results found')}
457	                description={t(
458	                  'No results match the filter criteria. Clear all filters and try again.',
459	                )}
460	                clearAllLabel={t('Clear all filters')}
461	              />
462	            ))}
463	        </TableView>
464	        {showPagination && (
465	          <Pagination
466	            variant="bottom"
467	            perPage={itemsPerPage}
468	            page={page}
469	            itemCount={finalFilteredData.length}
470	            onSetPage={onSetPage}
471	            onPerPageSelect={onPerPageSelect}
472	          />
473	        )}
474	      </PageSection>
475	    </span>
476	  );
477	};
478	
479	const StandardPage = <T,>(pageProps: StandardPageProps<T>) => {
480	  const { activeSort, compareFn, setActiveSort } = useTableSortContext();
481	  const internalPageRef = useRef(pageProps.page);
482	  const pageRef = pageProps.pageRef ?? internalPageRef;
483	
484	  const defaultSort = useMemo(() => {
485	    const field = pageProps.fieldsMetadata.find((fld) => fld.defaultSortDirection);
486	    return field?.defaultSortDirection && field?.resourceFieldId
487	      ? { direction: field.defaultSortDirection, resourceFieldId: field.resourceFieldId }
488	      : undefined;
489	  }, [pageProps.fieldsMetadata]);
490	
491	  if (activeSort.resourceFieldId) {
492	    return (
493	      <StandardPageInner
494	        {...pageProps}
495	        activeSort={activeSort}
496	        setActiveSort={setActiveSort}
497	        compareFn={compareFn}
498	        pageRef={pageRef}
499	      />
500	    );
501	  }
502	
503	  return (
504	    <TableSortContextProvider fields={pageProps.fieldsMetadata} defaultSort={defaultSort}>
505	      <TableSortContext.Consumer>
506	        {(sortProps) => <StandardPageInner {...pageProps} {...sortProps} pageRef={pageRef} />}
507	      </TableSortContext.Consumer>
508	    </TableSortContextProvider>
509	  );
510	};
511	
512	export default StandardPage;
